def unified_diff(text1: str, text2: str) -> str:
    """Generate unified diff between two texts."""
    lines1 = text1.splitlines()
    lines2 = text2.splitlines()
    result = []
    i = j = 0
    while i < len(lines1) or j < len(lines2):
        if i < len(lines1) and j < len(lines2) and lines1[i] == lines2[j]:
            result.append(f' {lines1[i]}')
            i += 1
            j += 1
        elif i < len(lines1) and (j >= len(lines2) or lines1[i] not in lines2[j:]):
            result.append(f'-{lines1[i]}')
            i += 1
        elif j < len(lines2):
            result.append(f'+{lines2[j]}')
            j += 1
    return '\n'.join(result)
